import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { noOrphanInvariantLayerRule } from "./no-orphan-invariant-layer.rule.js";

// Note: "invalid" cases for this rule trigger the @invariant decorator's invalid-namespace-nesting
// error at type-checker level, which prevents the linter phase from running. The decorator already
// enforces @invariant must be under @feature. Tests below cover valid scenarios only.

describe("no-orphan-invariant-layer rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, noOrphanInvariantLayerRule, "@a10n/blueprint-typespec");
  });

  // ─── valid ────────────────────────────────────────────────────────────────

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T025.T025_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.invariant_path:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.invariant_layer:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer
    it("@invariant under @feature in Products.* passes", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{ predicate: "p", why: "r" })
            op task_has_id(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T025.T025_02
    it("non-@invariant op anywhere is not flagged", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            op plain_op(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T025.T025_03
    it("@invariant nested under @feature (nested namespace) passes", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            namespace Sub {
              @invariant(#{ predicate: "p", why: "r" })
              op task_has_id(): void;
            }
          }
        `)
        .toBeValid();
    });
  });
});
